const { Server } = require('socket.io');

let io;

module.exports = {
 init: (httpServer) => {
 io = new Server(httpServer, {
 cors: {
 origin: process.env.VITE_FRONTEND_URL || 'http://localhost:5173',
 methods: ['GET', 'POST', 'PUT', 'DELETE'],
 credentials: true
 }
 });

 io.on('connection', (socket) => {
 console.log(` Client connected via WebSockets: ${socket.id}`);

 socket.on('join_user_room', (userId) => {
 // User joins their personal room for private notifications
 socket.join(userId);
 console.log(`User ${userId} joined their personal socket room.`);
 });

 socket.on('disconnect', () => {
 console.log(` Client disconnected: ${socket.id}`);
 });
 });

 return io;
 },
 getIO: () => {
 if (!io) {
 throw new Error('Socket.io not initialized!');
 }
 return io;
 }
};

const { Transaction } = require('../models');
const { Op, fn, col, literal } = require('sequelize');

// GET /api/forecast?months=3
// Dự báo dòng tiền dựa trên lịch sử 6 tháng — Linear Regression y = ax + b
exports.getForecast = async (req, res) => {
    try {
        const userId = req.user.id;
        const months = parseInt(req.query.months) || 3;

        // Lấy dữ liệu 6 tháng gần nhất, nhóm theo tháng
        const sixMonthsAgo = new Date();
        sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);

        const monthlyData = await Transaction.findAll({
            where: { user_id: userId, date: { [Op.gte]: sixMonthsAgo } },
            attributes: [
                [fn('date_trunc', 'month', col('date')), 'month'],
                [fn('SUM', literal('CASE WHEN type=\'INCOME\' THEN amount ELSE 0 END')), 'income'],
                [fn('SUM', literal('CASE WHEN type=\'EXPENSE\' THEN amount ELSE 0 END')), 'expense'],
            ],
            group: [fn('date_trunc', 'month', col('date'))],
            order: [[fn('date_trunc', 'month', col('date')), 'ASC']],
            raw: true
        });

        // Linear Regression: y = ax + b
        const linearRegression = (data) => {
            const n = data.length;
            if (n < 2) return { predict: (x) => data[0]?.y || 0 };
            const sumX = data.reduce((s, d) => s + d.x, 0);
            const sumY = data.reduce((s, d) => s + d.y, 0);
            const sumXY = data.reduce((s, d) => s + d.x * d.y, 0);
            const sumX2 = data.reduce((s, d) => s + d.x * d.x, 0);
            const denominator = n * sumX2 - sumX * sumX;
            const a = denominator !== 0 ? (n * sumXY - sumX * sumY) / denominator : 0;
            const b = (sumY - a * sumX) / n;
            return { a, b, predict: (x) => Math.max(0, Math.round((a * x + b) * 100) / 100) };
        };

        const incomes = monthlyData.map((d, i) => ({ x: i, y: parseFloat(d.income) || 0 }));
        const expenses = monthlyData.map((d, i) => ({ x: i, y: parseFloat(d.expense) || 0 }));

        const incomeModel = linearRegression(incomes);
        const expenseModel = linearRegression(expenses);

        // Dự báo N tháng tới
        const forecast = [];
        for (let i = 1; i <= months; i++) {
            const futureDate = new Date();
            futureDate.setMonth(futureDate.getMonth() + i);
            const predictedIncome = incomeModel.predict(monthlyData.length + i - 1);
            const predictedExpense = expenseModel.predict(monthlyData.length + i - 1);
            forecast.push({
                month: futureDate.toISOString().slice(0, 7),
                predictedIncome,
                predictedExpense,
                predictedNet: Math.round((predictedIncome - predictedExpense) * 100) / 100
            });
        }

        // Cảnh báo nếu chi > thu trong tương lai
        const warningMonth = forecast.find(f => f.predictedNet < 0);

        res.json({
            historical: monthlyData,
            forecast,
            warningMonth: warningMonth ? warningMonth.month : null
        });
    } catch (error) {
        console.error('Forecast error:', error);
        res.status(500).json({ message: 'Server error' });
    }
};

const express = require('express');
const cors = require('cors');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cookieParser = require('cookie-parser');
const { Sequelize } = require('sequelize');
const path = require('path');
const http = require('http'); // Add HTTP module
const socketConfig = require('./config/socket'); // Add Socket config
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;
const httpServer = http.createServer(app); // Create HTTP server

// Initialize Socket.io
socketConfig.init(httpServer);

// Security: HTTP headers theo chuẩn OWASP (HSTS, X-Frame-Options, CSP...)
app.use(helmet());
app.disable('x-powered-by');

// Rate Limiting Middleware (Bảo vệ chống Brute-force & DDoS)
const limiter = rateLimit({
 windowMs: 15 * 60 * 1000, // 15 phút
 max: 1000, // Tăng lên 1000 requests mỗi IP trong 15 phút để dev
 message: 'Quá nhiều yêu cầu từ IP này, vui lòng thử lại sau 15 phút.'
});

// Middleware
app.use(cors({
 origin: process.env.VITE_FRONTEND_URL || 'http://localhost:5173',
 credentials: true
}));
app.use(express.json());
app.use(cookieParser());
app.use('/api', limiter); // Áp dụng cho mọi API

// Phục vụ các file tĩnh trong thư mục uploads (Ví dụ: ảnh đại diện)
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

// Routes
app.use('/api/auth', require('./routes/authRoutes'));
app.use('/api/transactions', require('./routes/transactionRoutes'));
app.use('/api/debts', require('./routes/debtRoutes'));
app.use('/api/notifications', require('./routes/notificationRoutes'));
app.use('/api/wallets', require('./routes/walletRoutes'));
app.use('/api/families', require('./routes/familyRoutes'));
app.use('/api/goals', require('./routes/goalRoutes'));
app.use('/api/recurring', require('./routes/recurringRoutes'));
app.use('/api/analytics', require('./routes/analyticsRoutes'));
app.use('/api/users', require('./routes/userRoutes'));
app.use('/api/budgets', require('./routes/budgetRoutes'));
app.use('/api/categories', require('./routes/categoryRoutes'));
app.use('/api/admin', require('./routes/adminRoutes'));
app.use('/api/forecast', require('./routes/forecastRoutes'));

// Swagger API Documentation (truy cập: /api-docs)
const swaggerUi = require('swagger-ui-express');
const swaggerSpec = require('./config/swagger');
app.use('/api-docs', swaggerUi.serve, swaggerUi.setup(swaggerSpec));

// Cấu hình kết nối Database (Lấy từ biến môi trường Docker)
// Lưu ý: 'host' là tên service trong docker-compose ('db')
const sequelize = new Sequelize(
 process.env.DB_NAME || 'expense_tracker_db',
 process.env.DB_USER || 'admin',
 process.env.DB_PASS || 'password123',
 {
 host: process.env.DB_HOST || 'db', // Quan trọng: host phải là 'db'
 dialect: 'postgres',
 logging: false, // Tắt log SQL cho gọn
 }
);

// Route kiểm tra server sống hay chết
app.get('/', (req, res) => {
 res.send('<h1> Junkio Expense Tracker Backend is Running!</h1>');
});

// Route kiểm tra kết nối Database (Bảo vệ bởi auth)
app.get('/db-check', require('./middleware/authMiddleware'), async (req, res) => {
 try {
 await sequelize.authenticate();
 res.send(' Kết nối Database thành công!');
 } catch (error) {
 res.status(500).send(' Lỗi kết nối Database: ' + error.message);
 }
});

// Khởi động server (Dùng httpServer thay vì app.listen)
httpServer.listen(PORT, async () => {
 console.log(`Server is running on port ${PORT}`);

 // Thử kết nối DB ngay khi server chạy
 try {
 await sequelize.authenticate();
 console.log(' Database connected successfully!');

 // Khởi chạy hệ thống báo thức giao dịch định kỳ
 const { startCronJobs } = require('./services/cronJobs');
 startCronJobs();
 } catch (error) {
 console.error(' Unable to connect to the database:', error.message);
 }
});

const jwt = require('jsonwebtoken');

module.exports = (req, res, next) => {
    // Get token from header
    const token = req.header('x-auth-token');

    // Check if not token
    if (!token) {
        return res.status(401).json({ msg: 'No token, authorization denied' });
    }

    // Verify token
    try {
        const decoded = jwt.verify(token, process.env.JWT_SECRET || 'secret');
        req.user = decoded.user;
        next();
    } catch (err) {
        res.status(401).json({ msg: 'Token is not valid' });
    }
};

const { User } = require('../models');

async function makeAdmin() {
 const email = process.argv[2];

 if (!email) {
 console.log(' Vui lòng cung cấp email của tài khoản.');
 console.log(' Cách dùng: node make-admin.js <email>');
 console.log(' Ví dụ: node make-admin.js demo@junkio.com');
 process.exit(1);
 }

 try {
 const user = await User.findOne({ where: { email } });

 if (!user) {
 console.log(` Không tìm thấy user nào với email: ${email}`);
 process.exit(1);
 }

 user.role = 'admin';
 await user.save();

 console.log(` Cấp quyền Admin thành công cho tài khoản: ${email}`);
 process.exit(0);
 } catch (error) {
 console.error(' Lỗi khi cấp quyền:', error);
 process.exit(1);
 }
}

makeAdmin();

const cron = require('node-cron');
const { Op } = require('sequelize');
const { RecurringPattern, Transaction, Wallet, sequelize } = require('../models');

// Job chạy vào 0h00 mỗi ngày để kiểm tra các giao dịch định kỳ
const startCronJobs = () => {
 console.log(' Khởi tạo hệ thống Giao dịch định kỳ (Recurring Transactions Engine)...');

 // Mẫu cron: '0 0 * * *' có nghĩa là 0 phút 0 giờ mỗi ngày
 cron.schedule('0 0 * * *', async () => {
 console.log(' Đang kiểm tra các Giao dịch định kỳ cần thực thi trong ngày hôm nay...');
 const today = new Date().toISOString().split('T')[0];

 try {
 // Lấy tất cả patterns có next_run_date <= hôm nay và đang active
 const patterns = await RecurringPattern.findAll({
 where: {
 is_active: true,
 next_run_date: {
 [Op.lte]: today
 }
 }
 });

 if (patterns.length === 0) {
 console.log(' Không có giao dịch định kỳ nào cần thực thi hôm nay.');
 return;
 }

 for (const pattern of patterns) {
 const t = await sequelize.transaction();
 try {
 // 1. Tạo Transaction mới
 await Transaction.create({
 amount: pattern.amount,
 date: today,
 description: `[Tự Động] ${pattern.description || 'Giao dịch định kỳ'}`,
 type: pattern.type,
 wallet_id: pattern.wallet_id,
 category_id: pattern.category_id,
 user_id: pattern.user_id
 }, { transaction: t });

 // 2. Cập nhật số dư Ví (Wallet Balance)
 const wallet = await Wallet.findByPk(pattern.wallet_id, { transaction: t });
 if (wallet) {
 const amountFloat = parseFloat(pattern.amount);
 if (pattern.type === 'INCOME') {
 wallet.balance = parseFloat(wallet.balance) + amountFloat;
 } else if (pattern.type === 'EXPENSE') {
 wallet.balance = parseFloat(wallet.balance) - amountFloat;
 }
 await wallet.save({ transaction: t });
 }

 // 3. Tính toán next_run_date tiếp theo
 const nextDate = new Date(pattern.next_run_date);
 if (pattern.frequency === 'DAILY') {
 nextDate.setDate(nextDate.getDate() + 1);
 } else if (pattern.frequency === 'WEEKLY') {
 nextDate.setDate(nextDate.getDate() + 7);
 } else if (pattern.frequency === 'MONTHLY') {
 nextDate.setMonth(nextDate.getMonth() + 1);
 } else if (pattern.frequency === 'YEARLY') {
 nextDate.setFullYear(nextDate.getFullYear() + 1);
 }

 pattern.next_run_date = nextDate.toISOString().split('T')[0];
 await pattern.save({ transaction: t });

 // 4. Commit kết quả
 await t.commit();
 console.log(` Thực thi thành công mẫu định kỳ ID: ${pattern.id}`);

 } catch (err) {
 await t.rollback();
 console.error(` Lỗi khi thực thi mẫu định kỳ ID: ${pattern.id}`, err);
 }
 }
 } catch (error) {
 console.error(' Lỗi Engine Cron:', error);
 }
 });

 // Budget Alert: Chạy mỗi ngày lúc 8h sáng
 const { checkBudgetAlerts } = require('./budgetAlertService');
 cron.schedule('0 8 * * *', async () => {
 console.log(' Đang kiểm tra cảnh báo ngân sách...');
 await checkBudgetAlerts();
 });
};

module.exports = { startCronJobs };
